21	module fpga_self_test (
22	    input  wire        clk,
23	    input  wire        reset_n,
24	
25	    // Control
26	    input  wire        trigger,         // 1-cycle pulse from host (opcode 0x30)
27	    output reg         busy,            // High while tests are running
28	    output reg         result_valid,    // Pulses when all tests complete
29	    output reg  [4:0]  result_flags,    // Per-test PASS(1)/FAIL(0)
30	    output reg  [7:0]  result_detail,   // Diagnostic detail (first failing test ID + info)
31	
32	    // ADC raw capture interface (active during Test 4)
33	    input  wire [15:0] adc_data_in,     // Raw ADC sample (from ad9484_interface)
34	    input  wire        adc_valid_in,    // ADC sample valid
35	    output reg         capture_active,  // High during ADC capture window
36	    output reg  [15:0] capture_data,    // Captured ADC sample for USB readout
37	    output reg         capture_valid    // Pulse: new captured sample available
38	);
