41	// FSM States
42	// ============================================================================
43	localparam [3:0] ST_IDLE       = 4'd0,
44	                 ST_BRAM_WR    = 4'd1,
45	                 ST_BRAM_GAP   = 4'd2,   // 1-cycle gap: let last write complete
46	                 ST_BRAM_RD    = 4'd3,
47	                 ST_BRAM_CHK   = 4'd4,
48	                 ST_CIC_SETUP  = 4'd5,
49	                 ST_CIC_CHECK  = 4'd6,
50	                 ST_FFT_SETUP  = 4'd7,
51	                 ST_FFT_CHECK  = 4'd8,
52	                 ST_ARITH      = 4'd9,
53	                 ST_ADC_CAP    = 4'd10,
54	                 ST_DONE       = 4'd11;
55	
56	reg [3:0] state;
57	
58	// ============================================================================
59	// Test 0: BRAM Write/Read Pattern
60	// ============================================================================
61	// Uses a small embedded BRAM (64×16) with walking-1 pattern.
62	localparam BRAM_DEPTH = 64;
63	localparam BRAM_AW    = 6;
64	
65	reg  [15:0] test_bram [0:BRAM_DEPTH-1];
66	reg  [BRAM_AW-1:0] bram_addr;
67	reg  [15:0] bram_wr_data;
68	reg  [15:0] bram_rd_data;
69	reg         bram_pass;
70	
71	// Synchronous BRAM write — use walking_one directly to avoid pipeline lag
72	always @(posedge clk) begin
73	    if (state == ST_BRAM_WR)
74	        test_bram[bram_addr] <= walking_one(bram_addr);
75	end
76	
77	// Synchronous BRAM read (1-cycle latency)
78	always @(posedge clk) begin
79	    bram_rd_data <= test_bram[bram_addr];
80	end
81	
82	// Walking-1 pattern: address → (1 << (addr % 16))
83	function [15:0] walking_one;
84	    input [BRAM_AW-1:0] addr;
85	    begin
86	        walking_one = 16'd1 << (addr[3:0]);
87	    end
88	endfunction
89	
90	// ============================================================================
91	// Test 3: Arithmetic Check
92	// ============================================================================
93	// Verify saturating signed add (same logic as mti_canceller.v)
94	function [15:0] sat_add;
95	    input signed [15:0] a;
96	    input signed [15:0] b;
97	    reg signed [16:0] sum_full;
98	    begin
99	        sum_full = {a[15], a} + {b[15], b};
100	        if (sum_full > 17'sd32767)
101	            sat_add = 16'sd32767;
102	        else if (sum_full < -17'sd32768)
103	            sat_add = -16'sd32768;
104	        else
105	            sat_add = sum_full[15:0];
106	    end
107	endfunction
108	
109	reg arith_pass;
110	
111	// ============================================================================
112	// Counter / Control
113	// ============================================================================
114	reg [9:0] step_cnt;   // General-purpose step counter (up to 1024)
115	reg [9:0] adc_cap_cnt;
116	localparam ADC_CAP_SAMPLES = 256;  // Number of raw ADC samples to capture
117	
118	// Pipeline register for BRAM read verification (accounts for 1-cycle read latency)
119	reg [BRAM_AW-1:0] bram_rd_addr_d;
120	reg bram_rd_valid;
121	
